const prayers = [
  { name: 'Fajr',    time: $('Get prayer times').first().json.data.times.Fajr,    offset: 50 },
  { name: 'Dhuhr',   time: $('Get prayer times').first().json.data.times.Dhuhr,   offset: 40 },
  { name: 'Asr',     time: $('Get prayer times').first().json.data.times.Asr,     offset: 40 },
  { name: 'Maghrib', time: $('Get prayer times').first().json.data.times.Maghrib, offset: 25 },
  { name: 'Isha',    time: $('Get prayer times').first().json.data.times.Isha,    offset: 40 },
];

const dateString = $input.first().json['Readable Gregorian Date'];
const tz = 'Africa/Cairo';

const baseDate = DateTime.fromFormat(dateString, 'd MMM yyyy', { zone: tz });

function buildISO(dt) {
  return dt.set({ second: 0, millisecond: 0 }).toISO();
}

function calcStart(dt) {
  const flooredMinute = Math.floor(dt.minute / 10) * 10;
  return buildISO(dt.set({ minute: flooredMinute }));
}

function calcEnd(dt, offset) {
  const shifted = dt.plus({ minutes: offset });
  const roundedMinute = Math.ceil(shifted.minute / 10) * 10;
  if (roundedMinute === 60) {
    return buildISO(shifted.plus({ hours: 1 }).set({ minute: 0 }));
  }
  return buildISO(shifted.set({ minute: roundedMinute }));
}

const result = {};

for (const prayer of prayers) {
  const [h, m] = prayer.time.split(':').map(Number);
  const prayerDT = baseDate.set({ hour: h, minute: m, second: 0, millisecond: 0 });

  result[prayer.name] = {
    startTime: calcStart(prayerDT),
    endTime:   calcEnd(prayerDT, prayer.offset),
  };
}

return [{ json: result }];

